/// <summary>
/// SysOperation controller class for posting packing slips through the ETGSPAINSalesPackingSlipImport table
/// for the ETGSPAIN model.
/// </summary>
class ETGSPAINSalesPackingSlipImportPostController extends SysOperationServiceController
{
    ETGSPAINSalesPackingSlipImportPostContract contract;

}

Method.Source:
/// <summary>
/// Overwritten <c>new</c> method to perform the operation synchronously.
/// </summary>
/// <param name = "_className">IdentifierName</param>
/// <param name = "_methodName">IdentifierName</param>
protected void new(IdentifierName _className = classStr(ETGSPAINSalesPackingSlipImportPostService),
                   IdentifierName _methodName = methodStr(ETGSPAINSalesPackingSlipImportPostService, packingSlipImportPost))
{
    super(_className, _methodName, SysOperationExecutionMode::Synchronous);
}

/// <summary>
/// <c>construct</c> method to create an instance of the class.
/// </summary>
/// <param name = "_args">Args</param>
/// <returns>ETGSPAINSalesPackingSlipImportPostController</returns>
public static ETGSPAINSalesPackingSlipImportPostController construct(Args _args)
{
    ETGSPAINSalesPackingSlipImportPostController controller = new ETGSPAINSalesPackingSlipImportPostController();

    controller.parmArgs(_args);

    return  controller;
}

/// <summary>
/// Main static method of the class.
/// </summary>
/// <param name = "_args">Args</param>
public static void main(Args _args)
{
    ETGSPAINSalesPackingSlipImportPostController controller = ETGSPAINSalesPackingSlipImportPostController::construct(_args);
    controller.initContract();
    controller.startOperation();        
    controller.refreshCaller();
}

/// <summary>
/// Method to initialize the contract.
/// </summary>
public void initContract()
{
    contract = this.getDataContractObject() as ETGSPAINSalesPackingSlipImportPostContract;
    this.setContractAttributes();
    this.getRecordCollection();        
}

/// <summary>
/// Method to configure the contract attributes based on <c>Args</c>.
/// </summary>
private void setContractAttributes()
{
    if (this.parmArgs().menuItemName() == menuItemActionStr(ETGSPAINSalesPackingSlipImportPostController))
    {
        contract.initQuery();
        contract.parmCallerBuffer(null);
        contract.parmRefreshAll(true);
    }
    else
    {            
        contract.parmCallerBuffer(this.parmArgs().record());
        contract.parmRefreshAll(false);
    }
}

/// <summary>
/// Method to obtain the <c>recordCollection</c> variable via <c>Args</c>.
/// </summary>
private void getRecordCollection()
{
    Set recordCollection = new Set(Types::Int64);

    if (FormDataUtil::isFormDataSource(this.parmArgs().record()))
    {
        MultiSelectionHelper selection = MultiSelectionHelper::construct();
        selection.parmDatasource(FormDataUtil::getFormDataSource(this.parmArgs().record()));

        common selectedRecord = selection.getFirst();

        while (selectedRecord)
        {
            this.addToCollection(recordCollection, selectedRecord);
            selectedRecord = selection.getNext();
        }
    }
    else
    {
        this.addToCollection(recordCollection, contract.parmCallerBuffer());
    }

    contract.parmRecordCollection(recordCollection);
}

/// <summary>
/// Method to add <c>selectedRecord</c> into the <c>recordCollection</c> set.
/// </summary>
/// <param name = "_recordCollection">Set</param>
/// <param name = "selectedRecord">common</param>
private void addToCollection(Set _recordCollection, common selectedRecord)
{
    if (selectedRecord.RecId && !_recordCollection.in(selectedRecord.RecId))
    {
        _recordCollection.add(selectedRecord.RecId);
    }
}

/// <summary>
/// Method to refresh the caller after the process.
/// </summary>
private void refreshCaller()
{
    if (this.parmExecutionMode() == SysOperationExecutionMode::Synchronous && FormDataUtil::isFormDataSource(contract.parmCallerBuffer()))
    {
        FormDataUtil::getFormDataSource(contract.parmCallerBuffer()).research(true);
    }
}

/// <summary>
/// Method to return the title of the dialog of this class.
/// </summary>
/// <returns>ClassDescription</returns>
public ClassDescription defaultCaption()
{
    return "@ETGSPAINLabels:ETGSPAINSalesPackingSlipImportPostController";
}

/// <summary>
/// Method to get the contract of this class.
/// </summary>
/// <returns>ETGSPAINSalesPackingSlipImportPostContract</returns>
private ETGSPAINSalesPackingSlipImportPostContract getContract()
{
    return this.getDataContractObject() as ETGSPAINSalesPackingSlipImportPostContract;
}

/// <summary>
/// Method to set query dialog parameters in the class contract.
/// </summary>
/// <param name = "_displayQueryFilter">boolean</param>
/// <returns>boolean</returns>
public boolean parmDisplayQueryFilter(boolean _displayQueryFilter = displayQueryFilter)
{
    boolean	ret = super(_displayQueryFilter);

    if (FormDataUtil::isFormDataSource(this.parmArgs().record()))
    {
        ret = false;
    }
    else
    {
        ret = true;
    }

    contract.parmDisplayQueryFilter(ret);

    return ret;
}
